import{c as t,a7 as a,y as n,B as o}from"./chunks/framework.3cjvm90C.js";const m=JSON.parse('{"title":"PagedAttention","description":"介绍 PagedAttention 算法如何借鉴虚拟内存分页思想高效管理 KV Cache，消除内存碎片与浪费。","frontmatter":{"title":"PagedAttention","description":"介绍 PagedAttention 算法如何借鉴虚拟内存分页思想高效管理 KV Cache，消除内存碎片与浪费。"},"headers":[],"relativePath":"inference/vllm/page_attention.md","filePath":"inference/vllm/page_attention.md","lastUpdated":1782447613000}'),r={name:"inference/vllm/page_attention.md"};function i(l,e,g,s,p,d){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="pagedattention" tabindex="-1">PagedAttention <a class="header-anchor" href="#pagedattention" aria-label="Permalink to “PagedAttention”">​</a></h1><p>我们发现大语言模型（LLM）推理服务的性能瓶颈在于<strong>内存</strong>。在自回归解码过程中，所有输入的 Token 都会生成注意力机制中的 <strong>Key</strong> 和 <strong>Value</strong> 张量，这些张量被缓存在 GPU 内存中以生成后续 Token。这些缓存的 Key 和 Value 张量通常被称为 <strong>KV 缓存</strong>（KV Cache）。</p><h2 id="kv-缓存的挑战" tabindex="-1">KV 缓存的挑战 <a class="header-anchor" href="#kv-缓存的挑战" aria-label="Permalink to “KV 缓存的挑战”">​</a></h2><p>KV 缓存具备如下特点：</p><ul><li><strong>体积庞大</strong>：以 LLaMA-13B 为例，单个序列的 KV 缓存可占用高达 1.7GB 的 GPU 内存。</li><li><strong>动态变化</strong>：其大小取决于序列长度，而序列长度具有高度的可变性和不可预测性。</li></ul><p>因此，如何高效地管理 KV 缓存是一项巨大挑战。我们发现，现有系统中由于<strong>内存碎片</strong>和<strong>过度预留</strong>导致了 <strong>60%–80%</strong> 的内存浪费。</p><h2 id="pagedattention-的引入" tabindex="-1">PagedAttention 的引入 <a class="header-anchor" href="#pagedattention-的引入" aria-label="Permalink to “PagedAttention 的引入”">​</a></h2><p>在论文《Efficient Memory Management for Large Language Model Serving with PagedAttention》中，作者提出了 PagedAttention，一种受虚拟内存分页启发的新型算法。</p><p>内存分页技术最早用于操作系统（如 Windows 和 Unix）中，用于管理和分配系统内存中的页帧（Page Frame）。当系统内存不足时，它可以将暂时未被使用的内存区域换出，从而提升整体内存使用效率。PagedAttention 借鉴这一思想，对 LLM 推理中的 KV 缓存空间进行更高效的管理，从而实现动态内存分配，减少资源浪费。</p><img src="https://cdn.prod.website-files.com/67e1e36d3551f5a66e4095f5/68528e1f7e050381d596c900_AD_4nXdG0DxuPdeZHyw-AKAGwURyYhB8tN9xoqBbUKZ0cF3aa7FtZ909Z5sTNRydL8lnmHbZgNbh9s364Q7JnzaNOZgwhKgbtcTdihhzNbZWQ1nmnJ6Kg-Jc328uECmaVeiZaw_NGtFLirtOYce_JrLdTtUVOo4.png" alt="img" style="zoom:50%;"><p>Segmented Memory System (<a href="https://www.youtube.com/watch?v=p9yZNLeOj4s&amp;ref=blog.runpod.io" target="_blank" rel="noreferrer">Source</a>)</p><img src="https://cdn.prod.website-files.com/67e1e36d3551f5a66e4095f5/68528e1f7e050381d596c91f_AD_4nXc-N-FLOdHy9j6S7f8DJeuFb5WL-KDAaCwrv5Xtp-_z-SXU6UyJdUGzRmiIeZm-gvAcg5ScQ6Zm8U8E0uzRVyw70kasxXfA8KLAXgWn51YN1lDxl0IBQgt77_XGY_6-1Lhz_V3B2caz-v3QwaeOl9Gx0JHH.png" alt="img" style="zoom:50%;"><p>Paged Memory System (<a href="https://www.youtube.com/watch?v=p9yZNLeOj4s&amp;ref=blog.runpod.io" target="_blank" rel="noreferrer">Source</a>)</p><img src="https://lh7-us.googleusercontent.com/docsz/AD_4nXdJZ_p3OUnUQ1YtSTNef6iqMMGcHlntOzJCE_-ZlSfEfPqXet_EWJNFK7Hcpd9xDKBOqaOOmCNUCECCAmLfPidlEAhkCDjdWMImNaOL9tXvs6DgiH61ym2v-qSu3MpggyCXabhaB4UQGvNcapdSW9mHuy2k?key=jULPpW3gOjPzXuxrraGiJA" alt="img" style="zoom:50%;"><blockquote><p>Illustration comparing Memory management within the operating system and in LLM using vLLM (<a href="https://www.youtube.com/watch?v=5ZlavKF_98U&amp;t=351s&amp;ref=blog.runpod.io" target="_blank" rel="noreferrer">Source</a>).</p></blockquote><p>为了解决上述问题，我们提出了一种新的注意力算法 —— <strong>PagedAttention</strong>。该算法受到操作系统中 <strong>虚拟内存与分页机制</strong> 的启发。</p><h2 id="pagedattention-如何优化-kv-缓存使用效率" tabindex="-1">PagedAttention 如何优化 KV 缓存使用效率 <a class="header-anchor" href="#pagedattention-如何优化-kv-缓存使用效率" aria-label="Permalink to “PagedAttention 如何优化 KV 缓存使用效率”">​</a></h2><p>PagedAttention 通过动态分配内存块，充分利用先前未被使用的空间，从根本上减少了内存浪费。为了解决这一问题，我们先来了解传统系统如何浪费内存。</p><p>以 LLaMA-13B 模型为例，其参数占用约 26GB，在一块 40GB 显存的 NVIDIA A100 GPU 上就占去了 65% 的内存，剩余 30% 用于存放 KV 缓存。但传统系统将 KV 缓存保存在连续的内存空间中，即为每个请求预分配一块固定的、完整的内存区域。由于输入输出长度差异极大，这会导致大量空间无法被充分利用。</p><p>vLLM 团队将浪费归纳为三类：</p><ul><li><strong>内部碎片（Internal Fragmentation）</strong>：由于系统无法预知最终会生成多少 Token，因此会为序列预分配一块较大的内存区域，但最终未被完全使用。</li><li><strong>保留浪费（Reservation）</strong>：为了保证请求不中断，系统为整个序列持续预留内存块，即便部分内存未被使用，也不能被其他请求共享。</li><li><strong>外部碎片（External Fragmentation）</strong>：内存块固定大小与请求长度不匹配时，会在块之间产生无法复用的“空隙”。</li></ul><p><img src="https://cdn.prod.website-files.com/67e1e36d3551f5a66e4095f5/68528e1d7e050381d596c8ec_image.png" alt="img"></p><blockquote><p>图示：传统系统中三种 KV 缓存内存浪费形式（来源）</p></blockquote><p>与传统的注意力机制不同，PagedAttention 允许将连续的 key 和 value 张量存储在<strong>非连续的内存空间</strong>中。具体而言，PagedAttention 将每个序列的 KV 缓存划分为若干 <strong>块（block）</strong>，每个块包含固定数量 Token 的 Key 和 Value。在计算注意力时，PagedAttention 内核能够高效地识别并获取这些块。</p><img src="https://blog.vllm.ai/assets/figures/annimation0.gif" alt="img" style="zoom:50%;"><blockquote><p><strong>PagedAttention：KV 缓存被划分为多个块，块在内存中不要求连续存储。</strong></p></blockquote><p>由于块不要求在物理内存中连续，我们可以更灵活地管理 KV 数据，这与操作系统的虚拟内存类似。可以将：</p><ul><li>块类比为 <strong>页面（page）</strong>，</li><li>Token 类比为 <strong>字节（byte）</strong>，</li><li>序列类比为 <strong>进程（process）</strong>。</li></ul><p>序列的连续逻辑块通过一个 <strong>块映射表（block table）</strong> 映射到物理内存中的非连续块。这些物理块会随着新 Token 的生成而按需分配。</p><p>PagedAttention 的核心在于引入分页机制，动态分配内存块，不再要求内存连续。每个逻辑 KV 缓存与物理内存块之间的映射关系保存在一个称为“块表（Block Table）”的数据结构中。</p><img src="https://blog.vllm.ai/assets/figures/annimation1.gif" style="zoom:50%;"><blockquote><p>图示：PagedAttention 分页管理 KV 缓存的示意图（来源）</p></blockquote><p>PagedAttention 不仅消除了外部碎片，还最大程度减少了内部碎片，实现了近乎完美的内存使用效率。在 PagedAttention 中，<strong>内存浪费只发生在序列的最后一个块</strong>。据论文所述，传统实现中仅 20%–40% 的 KV 缓存被有效使用，而 vLLM 的 PagedAttention 将这一效率提升至接近 96%。</p><p>这种提升带来了显著的性能收益：</p><ul><li>可以批处理更多序列，</li><li>提高 GPU 利用率，</li><li>从而显著提升吞吐量（如上图性能结果所示）。</li></ul><h2 id="pagedattention-的另一个优势-高效的内存共享" tabindex="-1">PagedAttention 的另一个优势：高效的内存共享 <a class="header-anchor" href="#pagedattention-的另一个优势-高效的内存共享" aria-label="Permalink to “PagedAttention 的另一个优势：高效的内存共享”">​</a></h2><p>PagedAttention 通过其 <strong>块映射表（block table）</strong> 天然实现了内存共享。类似于操作系统中多个进程共享物理页面，PagedAttention 中的不同序列也可以通过将其逻辑块映射到同一个物理块，实现 <strong>块级别的共享</strong>。</p><p>为了确保共享的安全性，PagedAttention 会：</p><ul><li>追踪每个物理块的 <strong>引用计数（reference count）</strong>；</li><li>实施 <strong>写时复制（Copy-on-Write）机制</strong>，在需要修改共享内容时自动创建副本，避免数据冲突。</li></ul><img src="https://blog.vllm.ai/assets/figures/annimation3.gif" alt="img" style="zoom:50%;"><blockquote><p>示例：并行采样下的生成过程</p></blockquote><p>PagedAttention 的内存共享机制极大地减少了复杂采样算法的内存开销，比如并行采样和 beam search。根据测试结果，这些方法的内存使用最多可减少 <strong>55%</strong>，从而带来高达 <strong>2.2 倍</strong> 的吞吐量提升，使得这些采样方法在 LLM 服务中变得更加实用和高效。</p><p>PagedAttention 支持多个请求之间共享 KV 缓存内存，这是其动态映射设计的又一优势。以下几种推理解码策略都可以受益于此：</p><h3 id="_1-并行采样-parallel-sampling" tabindex="-1"><strong>1. 并行采样（parallel sampling）</strong> <a class="header-anchor" href="#_1-并行采样-parallel-sampling" aria-label="Permalink to “1. 并行采样（parallel sampling）”">​</a></h3><p>在 <strong>并行采样（parallel sampling）</strong> 中，从同一输入生成多个输出样本，例如生成多个候选答案供用户选择，在这种情况下，vLLM 可共享输入提示阶段的计算与内存。</p><p><img src="https://blog.vllm.ai/assets/figures/annimation2.gif" alt="img"></p><blockquote><p>图示：vLLM 在并行采样中共享 KV 缓存（来源）</p></blockquote><h3 id="_2-束搜索-beam-search" tabindex="-1">2. 束搜索（Beam Search） <a class="header-anchor" href="#_2-束搜索-beam-search" aria-label="Permalink to “2. 束搜索（Beam Search）”">​</a></h3><p>用于机器翻译等任务，每步保留最可能的几个候选路径，逐步扩展。vLLM 能够在不同 beam 分支间高效复用共享的前缀缓存。</p><h3 id="_3-共享前缀-shared-prefix" tabindex="-1">3. 共享前缀（Shared Prefix） <a class="header-anchor" href="#_3-共享前缀-shared-prefix" aria-label="Permalink to “3. 共享前缀（Shared Prefix）”">​</a></h3><p>多个请求使用相同系统提示词（system prompt）时，vLLM 会将其预存缓存共享，从而减少重复计算，提高效率。</p><h3 id="_4-混合解码策略-mixed-decoding" tabindex="-1">4. 混合解码策略（Mixed Decoding） <a class="header-anchor" href="#_4-混合解码策略-mixed-decoding" aria-label="Permalink to “4. 混合解码策略（Mixed Decoding）”">​</a></h3><p>如贪婪解码、Top-K 采样与 Beam Search 等混合并发使用，vLLM 可灵活管理不同策略下的缓存共享，无需强制统一解码方式，从而提升系统吞吐量与灵活性。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><p>PagedAttention 是 <strong>vLLM</strong> 的核心技术 —— 一个高性能、易用的大语言模型推理与服务引擎。它支持多种模型，显著提升内存利用率和推理吞吐量。</p><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to “Reference”">​</a></h2><ul><li><a href="https://blog.vllm.ai/2023/06/20/vllm.html" target="_blank" rel="noreferrer">https://blog.vllm.ai/2023/06/20/vllm.html</a></li></ul>',57)])])}const h=t(r,[["render",i]]);export{m as __pageData,h as default};
